# Switching between embedding backends with a consistent interface
from abc import ABC, abstractmethod
import numpy as np

class EmbedBackend(ABC):
    @abstractmethod
    def encode(self, texts: list[str]) -> np.ndarray: ...

class OpenAIBackend(EmbedBackend):
    def __init__(self, model="text-embedding-3-small"):
        from openai import OpenAI
        self.client = OpenAI()
        self.model = model

    def encode(self, texts):
        resp = self.client.embeddings.create(model=self.model, input=texts)
        vecs = np.array([d.embedding for d in sorted(resp.data, key=lambda x: x.index)], dtype="float32")
        return vecs / np.linalg.norm(vecs, axis=1, keepdims=True)

class SentenceTransformerBackend(EmbedBackend):
    def __init__(self, model_name="all-MiniLM-L6-v2"):
        from sentence_transformers import SentenceTransformer
        self.model = SentenceTransformer(model_name)

    def encode(self, texts):
        return self.model.encode(texts, normalize_embeddings=True)

# Drop-in swap between backends
backend: EmbedBackend = SentenceTransformerBackend()
vecs = backend.encode(["hello world", "machine learning"])
print(vecs.shape, vecs.dtype)
